				data-slot="animated-arrow-track"
				className="flex w-12 -translate-x-1/2 duration-500 ease-in-out group-hover/animated-arrow:translate-x-0"
			>
				<span className="flex size-6">
					<ArrowRight className="m-auto size-3" />
				</span>
				<span className="flex size-6">
					<ArrowRight className="m-auto size-3" />
